import{_ as e,a as t,b as n,c as i,d as l}from"./chunks/编辑配置.T0puvWjh.js";import{_ as d,o as r,c as o,a2 as s}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Tambah Telegram Channel","description":"","frontmatter":{},"headers":[],"relativePath":"ms-MY/upload/telegram.md","filePath":"ms-MY/upload/telegram.md","lastUpdated":1781962217000}'),h={name:"ms-MY/upload/telegram.md"};function c(m,a,p,u,k,b){return r(),o("div",null,[...a[0]||(a[0]=[s('<h1 id="tambah-telegram-channel" tabindex="-1">Tambah Telegram Channel <a class="header-anchor" href="#tambah-telegram-channel" aria-label="Permalink to &quot;Tambah Telegram Channel&quot;">​</a></h1><h2 id="perkara-yang-perlu-disediakan" tabindex="-1">Perkara Yang Perlu Disediakan <a class="header-anchor" href="#perkara-yang-perlu-disediakan" aria-label="Permalink to &quot;Perkara Yang Perlu Disediakan&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Requirement</th><th>Purpose</th></tr></thead><tbody><tr><td>Telegram account</td><td>Digunakan untuk mencipta bot dan storage channel.</td></tr><tr><td><code>@BotFather</code></td><td>Digunakan untuk mencipta Telegram bot.</td></tr><tr><td>Telegram channel</td><td>Destinasi akhir untuk menyimpan files.</td></tr><tr><td><code>@userinfobot</code></td><td>Digunakan untuk mendapatkan <code>Chat ID</code> channel.</td></tr></tbody></table><h2 id="di-mana-untuk-menambahnya" tabindex="-1">Di Mana Untuk Menambahnya <a class="header-anchor" href="#di-mana-untuk-menambahnya" aria-label="Permalink to &quot;Di Mana Untuk Menambahnya&quot;">​</a></h2><ol><li>Buka System Settings.</li><li>Pergi ke Upload Settings.</li><li>Klik Add Channel di penjuru kanan atas.</li><li>Pilih <code>Telegram</code>.</li></ol><h2 id="field-reference" tabindex="-1">Field Reference <a class="header-anchor" href="#field-reference" aria-label="Permalink to &quot;Field Reference&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Field</th><th>Fungsi</th><th>Required</th></tr></thead><tbody><tr><td>Channel name</td><td>Nama mesra untuk channel ini, contohnya &quot;Telegram Primary&quot;.</td><td>Required</td></tr><tr><td>Active</td><td>Mengaktifkan atau menyahaktifkan channel ini.</td><td>Recommended</td></tr><tr><td>Bot Token</td><td>Token untuk Telegram bot anda.</td><td>Required</td></tr><tr><td>Session ID (Chat ID)</td><td>ID untuk Telegram channel.</td><td>Required</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Gunakan hanya jika akses Telegram tidak stabil. Masukkan proxy URL penuh termasuk <code>https://</code>.</td><td>Optional</td></tr><tr><td>Remark</td><td>Nota untuk penyelenggaraan kemudian.</td><td>Optional</td></tr></tbody></table><h2 id="langkah-setup" tabindex="-1">Langkah Setup <a class="header-anchor" href="#langkah-setup" aria-label="Permalink to &quot;Langkah Setup&quot;">​</a></h2><h3 id="_1-cipta-telegram-bot" tabindex="-1">1. Cipta Telegram Bot <a class="header-anchor" href="#_1-cipta-telegram-bot" aria-label="Permalink to &quot;1. Cipta Telegram Bot&quot;">​</a></h3><ol><li>Buka Telegram dan cari <code>@BotFather</code>.</li><li>Buka chat dan klik <code>Start</code>.</li><li>Hantar <code>/newbot</code>.</li><li>Ikut prompt untuk masukkan bot display name.</li><li>Ikut prompt untuk masukkan bot username. Biasanya username perlu berakhir dengan <code>bot</code>.</li><li>Selepas bot dicipta, <code>@BotFather</code> akan memberi bot token.</li></ol><p>Token ini ialah <code>Bot Token</code> yang perlu dimasukkan dalam ImgBed.</p><p><img src="'+e+'" alt="Save the bot token" loading="lazy"></p><h3 id="_2-cipta-channel" tabindex="-1">2. Cipta Channel <a class="header-anchor" href="#_2-cipta-channel" aria-label="Permalink to &quot;2. Cipta Channel&quot;">​</a></h3><ol><li>Dalam Telegram, klik New Channel.</li><li>Masukkan channel name.</li><li>Selesaikan proses mencipta channel.</li></ol><p>Public dan private channel kedua-duanya boleh digunakan.</p><p><img src="'+t+'" alt="Create a channel" loading="lazy"></p><h3 id="_3-tambah-bot-ke-channel" tabindex="-1">3. Tambah Bot Ke Channel <a class="header-anchor" href="#_3-tambah-bot-ke-channel" aria-label="Permalink to &quot;3. Tambah Bot Ke Channel&quot;">​</a></h3><ol><li>Buka channel yang baru dicipta.</li><li>Buka channel settings.</li><li>Tambah member atau administrator.</li><li>Cari bot username yang anda cipta.</li><li>Tambah bot ke channel.</li></ol><p>Untuk upload yang paling stabil, berikan bot permission administrator.</p><p><img src="'+n+'" alt="Invite the bot to the channel" loading="lazy"></p><h3 id="_4-dapatkan-channel-id-dengan-user-info-get-id-idbot" tabindex="-1">4. Dapatkan Channel ID Dengan User Info - Get ID - IDbot <a class="header-anchor" href="#_4-dapatkan-channel-id-dengan-user-info-get-id-idbot" aria-label="Permalink to &quot;4. Dapatkan Channel ID Dengan User Info - Get ID - IDbot&quot;">​</a></h3><ol><li>Cari <code>@userinfobot</code> dalam Telegram. Display name biasanya <code>User Info - Get ID - IDbot</code>.</li><li>Buka chat dan klik <code>Start</code>.</li><li>Pilih <code>Channel</code> daripada pilihan yang diberi oleh bot.</li><li>Dalam message picker, pilih target channel dan hantar kepada <code>@userinfobot</code>.</li><li>Apabila <code>@userinfobot</code> memberi hasil, copy nombor yang ditunjukkan sebagai <code>Id: -100...</code>.</li></ol><p>Nombor yang bermula dengan <code>-100</code> ialah <code>Session ID (Chat ID)</code> yang diperlukan oleh ImgBed.</p><p><img src="'+i+'" alt="Get the channel ID" loading="lazy"></p><h3 id="_5-isi-telegram-channel-dalam-imgbed" tabindex="-1">5. Isi Telegram Channel Dalam ImgBed <a class="header-anchor" href="#_5-isi-telegram-channel-dalam-imgbed" aria-label="Permalink to &quot;5. Isi Telegram Channel Dalam ImgBed&quot;">​</a></h3><p>Kembali ke channel configuration dialog dan isi seperti berikut:</p><table tabindex="0"><thead><tr><th>UI Field</th><th>Value</th></tr></thead><tbody><tr><td>Channel Identifier</td><td>Nama channel tersuai, contohnya <code>TelegramPrimary</code>.</td></tr><tr><td>Active</td><td>Recommended.</td></tr><tr><td>Bot Token</td><td>Bot token daripada <code>@BotFather</code>.</td></tr><tr><td>Session ID (Chat ID)</td><td>Nombor <code>-100...</code> yang diberi oleh <code>@userinfobot</code>.</td></tr><tr><td>Relay Proxy URL (optional)</td><td>Hanya jika perlu, contohnya <code>https://your-tg-proxy.example.com</code>.</td></tr><tr><td>Remark</td><td>Nota pilihan.</td></tr></tbody></table><p>Klik Save apabila selesai.</p><p><img src="'+l+`" alt="Edit the configuration" loading="lazy"></p><h2 id="cara-menyemak" tabindex="-1">Cara Menyemak <a class="header-anchor" href="#cara-menyemak" aria-label="Permalink to &quot;Cara Menyemak&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Check</th><th>Cara Menyemak</th></tr></thead><tbody><tr><td>Channel card muncul</td><td>Selepas save, halaman Upload Settings patut memaparkan Telegram channel card.</td></tr><tr><td>Channel boleh diaktifkan</td><td>Active switch patut kekal on.</td></tr><tr><td>Configuration disimpan</td><td>Detail view patut menunjukkan Bot Token dan Chat ID telah disimpan.</td></tr><tr><td>Upload berfungsi</td><td>Upload test image dan pastikan ia muncul dalam Telegram channel sasaran.</td></tr></tbody></table><h2 id="quick-checklist" tabindex="-1">Quick Checklist <a class="header-anchor" href="#quick-checklist" aria-label="Permalink to &quot;Quick Checklist&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Cipta bot dengan @BotFather</span></span>
<span class="line"><span>-&gt; Simpan Bot Token</span></span>
<span class="line"><span>-&gt; Cipta Telegram channel</span></span>
<span class="line"><span>-&gt; Tambah bot ke channel dan beri administrator permissions</span></span>
<span class="line"><span>-&gt; Cari @userinfobot dan pilih Channel</span></span>
<span class="line"><span>-&gt; Forward mana-mana message daripada channel kepada @userinfobot</span></span>
<span class="line"><span>-&gt; Copy Id: -100... yang dipulangkan</span></span>
<span class="line"><span>-&gt; Masukkan Bot Token dan Chat ID dalam ImgBed</span></span>
<span class="line"><span>-&gt; Save dan upload test image</span></span></code></pre></div><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ol><li>Telegram bots: <a href="https://core.telegram.org/bots" target="_blank" rel="noreferrer">https://core.telegram.org/bots</a></li><li>Telegram Bot API: <a href="https://core.telegram.org/bots/api" target="_blank" rel="noreferrer">https://core.telegram.org/bots/api</a></li></ol>`,35)])])}const C=d(h,[["render",c]]);export{f as __pageData,C as default};
